mapper.select:
SELECT * FROM adoption_contract 
WHERE 1=1

    AND contract_no LIKE CONCAT('%', #{contractNo}, '%')


    AND sign_date >= #{startDate}


    AND sign_date <= #{endDate}

ORDER BY sign_date DESC, contract_id DESC

SELECT * FROM adoption_contract 
WHERE sign_date BETWEEN #{startDate} AND #{endDate}
ORDER BY sign_date ASC, contract_id ASC

mapper.update:
UPDATE adoption_contract 
SET file_url = #{fileUrl}
WHERE contract_id = #{contractId}

UPDATE adoption_contract 
SET adopter_sign_url = #{adopterSignUrl}
WHERE contract_id = #{contractId}

UPDATE adoption_contract 
SET shelter_sign_url = #{shelterSignUrl}
WHERE contract_id = #{contractId}

mapper.select:
SELECT * FROM adoption_contract 
ORDER BY sign_date DESC, contract_id DESC
LIMIT #{limit}
